interface RetryOptions {
  maxAttempts: number;
  delayMs: number;
  maxDelayMs: number;
  multiplier: number;
  jitter: boolean;
  retryOn?: (error: Error) => boolean;
}

const defaultOptions: RetryOptions = {
  maxAttempts: 3,
  delayMs: 1000,
  maxDelayMs: 30000,
  multiplier: 2,
  jitter: true,
  retryOn: () => true
};

async function retry<T>(
  fn: () => Promise<T>,
  options: Partial<RetryOptions> = {}
): Promise<T> {
  const opts = { ...defaultOptions, ...options };
  let lastError: Error | undefined;

  for (let attempt = 1; attempt <= opts.maxAttempts; attempt++) {
    try {
      return await fn();
    } catch (error) {
      lastError = error as Error;

      if (attempt === opts.maxAttempts) break;

      if (!opts.retryOn(error as Error)) break;

      const delay = calculateDelay(attempt, opts);
      await sleep(delay);

      console.log(`Attempt ${attempt} failed, retrying in ${delay}ms...`);
    }
  }

  throw lastError;
}

function calculateDelay(attempt: number, options: RetryOptions): number {
  let delay = options.delayMs * Math.pow(options.multiplier, attempt - 1);
  delay = Math.min(delay, options.maxDelayMs);

  if (options.jitter) {
    delay = delay * (0.5 + Math.random() * 0.5);
  }

  return Math.round(delay);
}

function sleep(ms: number): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, ms));
}

// Usage
async function fetchUserData(userId: string) {
  return retry(async () => {
    const response = await fetch(`/api/users/${userId}`);
    if (!response.ok) throw new Error('Failed to fetch user');
    return response.json();
  }, {
    maxAttempts: 5,
    delayMs: 500,
    maxDelayMs: 10000,
    retryOn: (error) => error.message.includes('Timeout') || error.status >= 500
  });
}

interface Connection {
  id: string;
  isConnected: boolean;
  lastUsed: Date;
  execute(query: string): Promise<any>;
  close(): Promise<void>;
}

interface PoolOptions {
  min: number;
  max: number;
  acquireTimeout: number;
  idleTimeout: number;
  creationTimeout: number;
}

class ConnectionPool {
  private available: Connection[] = [];
  private inUse: Map<Connection, string> = new Map();
  private options: Required<PoolOptions>;
  private nextId = 1;

  constructor(options: Partial<PoolOptions>) {
    this.options = {
      min: 2,
      max: 10,
      acquireTimeout: 5000,
      idleTimeout: 30000,
      creationTimeout: 10000,
      ...options
    };

    // Pre-fill minimum connections
    for (let i = 0; i < this.options.min; i++) {
      this.available.push(this.createConnection());
    }
  }

  async acquire(clientId: string): Promise<Connection> {
    const timeout = new Promise<Connection>((_, reject) =>
      setTimeout(() => reject(new Error('Acquire timeout')), this.options.acquireTimeout)
    );

    const connectionPromise = this.tryAcquire(clientId);
    return Promise.race([connectionPromise, timeout]);
  }

  private async tryAcquire(clientId: string): Promise<Connection> {
    if (this.available.length > 0) {
      const connection = this.available.shift()!;
      this.inUse.set(connection, clientId);
      return connection;
    }

    if (this.available.length + this.inUse.size < this.options.max) {
      const connection = this.createConnection();
      this.inUse.set(connection, clientId);
      return connection;
    }

    return new Promise((resolve) => {
      const checkInterval = setInterval(() => {
        if (this.available.length > 0) {
          clearInterval(checkInterval);
          const connection = this.available.shift()!;
          this.inUse.set(connection, clientId);
          resolve(connection);
        }
      }, 100);
    });
  }

  release(connection: Connection, clientId: string): void {
    this.inUse.delete(connection);
    connection.lastUsed = new Date();

    if (this.available.length < this.options.min) {
      this.available.push(connection);
    } else {
      connection.close();
    }
  }

  private createConnection(): Connection {
    const id = `conn-${this.nextId++}`;
    return {
      id,
      isConnected: true,
      lastUsed: new Date(),
      async execute(query: string) { /* ... */ },
      async close() { this.isConnected = false; }
    };
  }

  getStats(): { available: number; inUse: number; total: number } {
    return {
      available: this.available.length,
      inUse: this.inUse.size,
      total: this.available.length + this.inUse.size
    };
  }
}

export { ConnectionPool };

interface RateLimitConfig {
  windowMs: number;
  maxRequests: number;
  keyGenerator?: (req: any) => string;
}

class RateLimiter {
  private stores: Map<string, { count: number; resetTime: number }> = new Map();
  private config: RateLimitConfig;

  constructor(config: RateLimitConfig) {
    this.config = config;
  }

  async checkLimit(req: any): Promise<{ allowed: boolean; remaining: number; resetAt: Date }> {
    const key = this.config.keyGenerator ? this.config.keyGenerator(req) : req.ip;
    const now = Date.now();

    let record = this.stores.get(key);

    if (!record || now > record.resetTime) {
      record = {
        count: 0,
        resetTime: now + this.config.windowMs
      };
      this.stores.set(key, record);
    }

    if (record.count >= this.config.maxRequests) {
      return {
        allowed: false,
        remaining: 0,
        resetAt: new Date(record.resetTime)
      };
    }

    record.count++;

    return {
      allowed: true,
      remaining: this.config.maxRequests - record.count,
      resetAt: new Date(record.resetTime)
    };
  }

  cleanup(): void {
    const now = Date.now();
    for (const [key, record] of this.stores.entries()) {
      if (now > record.resetTime) {
        this.stores.delete(key);
      }
    }
  }

  reset(key?: string): void {
    if (key) {
      this.stores.delete(key);
    } else {
      this.stores.clear();
    }
  }

  getUsage(key: string): { count: number; limit: number; remaining: number } | null {
    const record = this.stores.get(key);
    if (!record) return null;

    return {
      count: record.count,
      limit: this.config.maxRequests,
      remaining: Math.max(0, this.config.maxRequests - record.count)
    };
  }
}

// Express middleware
function rateLimitMiddleware(config: RateLimitConfig) {
  const limiter = new RateLimiter(config);

  return async (req: any, res: any, next: any) => {
    const result = await limiter.checkLimit(req);

    res.set('X-RateLimit-Limit', String(config.maxRequests));
    res.set('X-RateLimit-Remaining', String(result.remaining));
    res.set('X-RateLimit-Reset', String(result.resetAt.getTime()));

    if (!result.allowed) {
      res.status(429).json({
        error: 'Too many requests',
        retryAfter: Math.ceil((result.resetAt.getTime() - Date.now()) / 1000)
      });
      return;
    }

    next();
  };
}

export { RateLimiter, rateLimitMiddleware };

interface HealthCheckResult {
  status: 'healthy' | 'unhealthy' | 'degraded';
  checks: Map<string, CheckResult>;
  timestamp: Date;
  duration: number;
}

interface CheckResult {
  status: 'ok' | 'error';
  message?: string;
  duration: number;
  details?: any;
}

class HealthChecker {
  private checks: Map<string, () => Promise<CheckResult>> = new Map();

  registerCheck(name: string, checkFn: () => Promise<CheckResult>): void {
    this.checks.set(name, checkFn);
  }

  async checkAll(): Promise<HealthCheckResult> {
    const startTime = Date.now();
    const results = new Map<string, CheckResult>();
    let hasErrors = false;
    let hasWarnings = false;

    const checkPromises = Array.from(this.checks.entries()).map(async ([name, checkFn]) => {
      const checkStart = Date.now();
      try {
        const result = await checkFn();
        result.duration = Date.now() - checkStart;
        results.set(name, result);
        if (result.status === 'error') hasErrors = true;
        if (result.details?.warning) hasWarnings = true;
      } catch (error) {
        results.set(name, {
          status: 'error',
          message: error instanceof Error ? error.message : 'Unknown error',
          duration: Date.now() - checkStart
        });
        hasErrors = true;
      }
    });

    await Promise.all(checkPromises);

    const overallStatus: 'healthy' | 'unhealthy' | 'degraded' = 
      hasErrors ? 'unhealthy' : hasWarnings ? 'degraded' : 'healthy';

    return {
      status: overallStatus,
      checks: results,
      timestamp: new Date(),
      duration: Date.now() - startTime
    };
  }

  async checkCritical(): Promise<HealthCheckResult> {
    const criticalChecks = new Map<string, () => Promise<CheckResult>>();

    for (const [name, checkFn] of this.checks.entries()) {
      if (name.startsWith('critical:')) {
        criticalChecks.set(name.replace('critical:', ''), checkFn);
      }
    }

    const originalChecks = this.checks;
    this.checks = criticalChecks;

    try {
      return await this.checkAll();
    } finally {
      this.checks = originalChecks;
    }
  }
}

// Example checks
const checker = new HealthChecker();
checker.registerCheck('database', async () => {
  try {
    await db.ping();
    return { status: 'ok', message: 'Database connection successful' };
  } catch (error) {
    return { status: 'error', message: 'Database connection failed' };
  }
});
checker.registerCheck('redis', async () => {
  try {
    await redis.ping();
    return { status: 'ok', message: 'Redis connection successful' };
  } catch (error) {
    return { status: 'error', message: 'Redis connection failed' };
  }
});

interface ConfigSchema {
  port: number;
  host: string;
  database: {
    url: string;
    poolSize: number;
    ssl: boolean;
  };
  redis: {
    url: string;
    password?: string;
  };
  jwt: {
    secret: string;
    expiresIn: string;
  };
  logging: {
    level: 'debug' | 'info' | 'warn' | 'error';
    format: 'json' | 'pretty';
  };
  features: {
    enableNewCheckout: boolean;
    maxUploadSize: number;
  };
}

class ConfigManager {
  private config: Partial<ConfigSchema> = {};
  private validators: Map<string, (value: any) => boolean> = new Map();

  define<T extends keyof ConfigSchema>(
    key: T,
    defaultValue: ConfigSchema[T],
    envVar: string,
    validator?: (value: any) => boolean
  ): void {
    const value = process.env[envVar];

    if (value !== undefined) {
      this.config[key] = this.parseValue(value, defaultValue);
    } else {
      this.config[key] = defaultValue;
    }

    if (validator) {
      this.validators.set(key, validator);
    }
  }

  get<T extends keyof ConfigSchema>(key: T): ConfigSchema[T] {
    const value = this.config[key];
    if (value === undefined) {
      throw new Error(`Configuration key '${key}' is not defined`);
    }

    const validator = this.validators.get(key);
    if (validator && !validator(value)) {
      throw new Error(`Configuration validation failed for '${key}'`);
    }

    return value as ConfigSchema[T];
  }

  private parseValue(value: string, defaultValue: any): any {
    if (typeof defaultValue === 'number') return Number(value);
    if (typeof defaultValue === 'boolean') return value.toLowerCase() === 'true';
    if (defaultValue instanceof Array) return value.split(',');
    return value;
  }

  validate(): void {
    for (const [key, validator] of this.validators.entries()) {
      const value = this.config[key];
      if (value !== undefined && !validator(value)) {
        throw new Error(`Invalid configuration value for '${key}': ${value}`);
      }
    }
  }

  toObject(): ConfigSchema {
    return this.config as ConfigSchema;
  }
}

// Usage
const config = new ConfigManager();
config.define('port', 3000, 'PORT', (v: number) => v > 0 && v < 65536);
config.define('host', 'localhost', 'HOST');
config.define('database.url', 'mongodb://localhost:27017/myapp', 'DATABASE_URL');
config.define('database.poolSize', 10, 'DB_POOL_SIZE', (v: number) => v > 0);
config.define('logging.level', 'info', 'LOG_LEVEL', (v: string) => ['debug', 'info', 'warn', 'error'].includes(v));
config.validate();

export const appConfig = config.toObject();

type LogLevel = 'trace' | 'debug' | 'info' | 'warn' | 'error' | 'fatal';

interface LogEntry {
  timestamp: string;
  level: LogLevel;
  message: string;
  service: string;
  requestId?: string;
  userId?: string;
  context: Record<string, any>;
  stack?: string;
}

class StructuredLogger {
  private service: string;
  private minLevel: LogLevel;
  private output: (entry: LogEntry) => void;
  private contextStack: Record<string, any>[] = [];

  constructor(service: string, minLevel: LogLevel = 'info', output?: (entry: LogEntry) => void) {
    this.service = service;
    this.minLevel = minLevel;
    this.output = output || this.defaultOutput;
  }

  info(message: string, context?: Record<string, any>): void {
    this.log('info', message, context);
  }

  error(message: string, context?: Record<string, any>, error?: Error): void {
    this.log('error', message, context, error);
  }

  warn(message: string, context?: Record<string, any>): void {
    this.log('warn', message, context);
  }

  debug(message: string, context?: Record<string, any>): void {
    this.log('debug', message, context);
  }

  trace(message: string, context?: Record<string, any>): void {
    this.log('trace', message, context);
  }

  child(context: Record<string, any>): StructuredLogger {
    const childLogger = new StructuredLogger(this.service, this.minLevel, this.output);
    childLogger.contextStack = [...this.contextStack, context];
    return childLogger;
  }

  private log(level: LogLevel, message: string, context?: Record<string, any>, error?: Error): void {
    if (this.getLevelIndex(level) < this.getLevelIndex(this.minLevel)) return;

    const entry: LogEntry = {
      timestamp: new Date().toISOString(),
      level,
      message,
      service: this.service,
      requestId: this.contextStack.find(c => c.requestId)?.requestId,
      userId: this.contextStack.find(c => c.userId)?.userId,
      context: this.mergeContext(context),
      stack: error?.stack
    };

    this.output(entry);
  }

  private mergeContext(extra: Record<string, any> | undefined): Record<string, any> {
    let merged: Record<string, any> = {};
    for (const ctx of this.contextStack) {
      merged = { ...merged, ...ctx };
    }
    if (extra) {
      merged = { ...merged, ...extra };
    }
    return merged;
  }

  private defaultOutput(entry: LogEntry): void {
    console.log(JSON.stringify(entry));
  }

  private getLevelIndex(level: LogLevel): number {
    const levels: LogLevel[] = ['trace', 'debug', 'info', 'warn', 'error', 'fatal'];
    return levels.indexOf(level);
  }
}

// Usage with request context
const logger = new StructuredLogger('user-service');

app.use((req, res, next) => {
  const requestLogger = logger.child({
    requestId: req.headers['x-request-id'],
    userId: req.user?.id,
    ip: req.ip
  });

  requestLogger.info('Request received', { method: req.method, path: req.path });
  next();
});

interface FeatureFlag {
  name: string;
  enabled: boolean;
  rolloutPercentage?: number;
  targetUsers?: string[];
  conditions?: Record<string, any>;
  description: string;
  createdBy: string;
  createdAt: Date;
}

class FeatureFlagManager {
  private flags: Map<string, FeatureFlag> = new Map();
  private listeners: Set<(flagName: string, enabled: boolean) => void> = new Set();

  registerFlag(flag: FeatureFlag): void {
    this.flags.set(flag.name, flag);
  }

  isEnabled(flagName: string, context?: Record<string, any>): boolean {
    const flag = this.flags.get(flagName);

    if (!flag) {
      return false;
    }

    if (!flag.enabled) {
      return false;
    }

    // Check target users
    if (flag.targetUsers && context?.userId) {
      if (!flag.targetUsers.includes(context.userId)) {
        return false;
      }
    }

    // Check rollout percentage
    if (flag.rolloutPercentage !== undefined && flag.rolloutPercentage < 100) {
      const hash = this.hashCode(context?.userId || 'anonymous');
      const percentage = Math.abs(hash % 100);

      if (percentage >= flag.rolloutPercentage) {
        return false;
      }
    }

    // Check custom conditions
    if (flag.conditions && context) {
      return this.evaluateConditions(flag.conditions, context);
    }

    return true;
  }

  private hashCode(str: string): number {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
      const char = str.charCodeAt(i);
      hash = ((hash << 5) - hash) + char;
      hash = hash & hash;
    }
    return hash;
  }

  private evaluateConditions(conditions: Record<string, any>, context: Record<string, any>): boolean {
    return Object.entries(conditions).every(([key, expected]) => {
      return context[key] === expected;
    });
  }

  toggleFlag(flagName: string, enabled: boolean): void {
    const flag = this.flags.get(flagName);
    if (flag) {
      flag.enabled = enabled;
      this.notifyListeners(flagName, enabled);
    }
  }

  onFlagChange(listener: (flagName: string, enabled: boolean) => void): void {
    this.listeners.add(listener);
  }

  private notifyListeners(flagName: string, enabled: boolean): void {
    this.listeners.forEach(listener => listener(flagName, enabled));
  }
}

// Usage
const featureFlags = new FeatureFlagManager();
featureFlags.registerFlag({
  name: 'newCheckout',
  enabled: true,
  rolloutPercentage: 50,
  description: 'New checkout flow',
  createdBy: 'admin',
  createdAt: new Date()
});

if (featureFlags.isEnabled('newCheckout', { userId: 'user123' })) {
  showNewCheckout();
} else {
  showOldCheckout();
}

import React, { Component, ErrorInfo, ReactNode } from 'react';

interface Props {
  children: ReactNode;
  fallback?: ReactNode | ((error: Error, reset: () => void) => ReactNode);
  onError?: (error: Error, errorInfo: ErrorInfo) => void;
  retryCallback?: () => Promise<void>;
}

interface State {
  hasError: boolean;
  error: Error | null;
  errorInfo: ErrorInfo | null;
}

class ErrorBoundary extends Component<Props, State> {
  constructor(props: Props) {
    super(props);
    this.state = { hasError: false, error: null, errorInfo: null };
  }

  static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error, errorInfo: null };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo): void {
    this.setState({ errorInfo });

    // Log error to monitoring service
    console.error('Error caught by ErrorBoundary:', error, errorInfo);

    if (this.props.onError) {
      this.props.onError(error, errorInfo);
    }

    // Send to error tracking service
    errorTrackingService.captureException(error, {
      componentStack: errorInfo.componentStack,
      timestamp: new Date().toISOString()
    });
  }

  resetErrorBoundary = (): void => {
    this.setState({ hasError: false, error: null, errorInfo: null });

    if (this.props.retryCallback) {
      this.props.retryCallback().catch(console.error);
    }
  };

  render(): ReactNode {
    if (this.state.hasError) {
      if (this.props.fallback) {
        if (typeof this.props.fallback === 'function') {
          return this.props.fallback(this.state.error!, this.resetErrorBoundary);
        }
        return this.props.fallback;
      }

      return (
        <div className="error-boundary">
          <h2>Something went wrong</h2>
          <p>{this.state.error?.message}</p>
          <button onClick={this.resetErrorBoundary}>
            Try again
          </button>
        </div>
      );
    }

    return this.props.children;
  }
}

export default ErrorBoundary;
